#include <stdio.h>
int main() {
	int n;
	scanf("%d", &n);
	unsigned long long ans = 6;
	unsigned long long pow = 16;

	for(int i = 1; i < n; i++) {
		ans *= pow;
		ans %= 1000000007;
		pow *= pow;
		pow %= 1000000007;
	}

	printf("%llu\n", ans);

}

