#![allow(clippy::many_single_char_names, dead_code, unused_imports, unused_macros, unused_variables)]
#![recursion_limit = "1000"]
use std::{cmp::Reverse, collections::*, fmt::Binary, hash::Hash, io::{stdin, stdout, BufWriter, Read, StdinLock, StdoutLock, Write}, iter::FromIterator, mem::swap, ops::Rem};

macro_rules! parse {
    (check $n: expr, $t: ty) => { std::str::from_utf8_unchecked($n).parse::<$t>().unwrap() };
    ($n: expr, $t: ty) => {
        if cfg!(debug_assertions) {
            parse!(check $n, $t)
        } else {
            #[allow(unused_comparisons)] {
                if <$t>::default()-1 > 0 {
                    parse!(unsigned $n, $t)
                } else {
                    parse!(signed $n, $t)
                }
            }
        }
    };
    (unsigned $n: expr, $t: ty) => {{
        let mut num = 0;

        for d in $n {
            num = num*10 + (*d - b'0') as $t;
        }
        num
    }};
    (signed $n: expr, $t: ty) => {{
        if $n.get_unchecked(0) == &b'-' {
            let mut num = 0;

            for d in &$n[1..] {
                num = num*10 - (*d - b'0') as $t;
            }
            num
        } else {
            parse!(unsigned $n, $t)
        }
    }};
}

macro_rules! read {
    ($r: expr) => { $r.read() };
    ($r: expr, str) => { String::from_utf8_unchecked($r.read().into()) };
    ($r: expr, f32) => { read!(check $r, f32) };
    ($r: expr, f64) => { read!(check $r, f64) };
    (check $r: expr, $t: ty) => {{
        let n = $r.read();
        parse!(check n, $t)
    }};
    ($r: expr, $t: ty) => {{
        let n = $r.read();
        parse!(n, $t)
    }}
}

macro_rules! fill {
    (declare mut $r: expr, $t: ty, $($x: ident),+) => {
        $(
            let mut $x = read!($r, $t);
        )+
    };
    (declare $r: expr, $t: ty, $($x: ident),+) => {
        $(
            let $x = read!($r, $t);
        )+
    };
    ($r: expr, $t: ty, $($x: ident),+) => {
        $(
            $x = read!($r, $t);
        )+
    }
}

macro_rules! read_vec {
    (const $r: expr, $t: ty, $n: expr) => {{
        let mut v = [0; $n];
        for x in &mut v {
            *x = read!($r, $t);
        }
        v
    }};
    (fill $r: expr, $t: ty, $v: expr, $n: expr) => {
        for x in &mut $v[..$n] {
            *x = read!($r, $t);
        }
    };
    ($r: expr, str, $n: expr) => {{
        let mut v = Vec::with_capacity($n);
        for _ in 0..$n {
            v.push(read!($r, str));
            // v.push(String::from_utf8_unchecked(read!($r).into()));
        }
        v
    }};
    ($r: expr, $t: ty, $n: expr) => {{
        let mut v = Vec::with_capacity($n);
        for _ in 0..$n {
            v.push(read!($r, $t));
        }
        v
    }};
    ($r: expr, str) => {{
        let mut v = Vec::with_capacity(10_000);
        loop {
            let (tmp, b) = $r.read_with_lf_check();
            v.push(String::from_utf8_unchecked(tmp.into()));
            if b {
                break v;
            }
        }
    }};
    ($r: expr, $t: ty) => {{
        let mut v = Vec::with_capacity(10_000);
        loop {
            let (tmp, b) = $r.read_with_lf_check();
            v.push(read!($r, $t));
            if b {
                break v;
            }
        }
    }};
    ($r: expr) => { read_vec!($r, str) };
    ($r: expr, $n: expr) => { read_vec!($r, str, $n) };
}

macro_rules! w {
    ($w: expr $(, $args: expr)*) => {
        write!($w $(, $args)*).unwrap();
    };
}

macro_rules! wl {
    ($w: expr $(, $args: expr)*) => {
        writeln!($w $(, $args)*).unwrap();
    };
}


macro_rules! void {
    ($r: expr) => { void!($r, 2); };
    ($r: expr, 1) => {
        $r.cursor += 1;
        loop {
            if $r.buf.get_unchecked($r.cursor) <= &b' ' {
                if $r.cursor >= $r.buf_len {
                    $r.buf_len = $r.stdin.read(&mut $r.buf).unwrap();
                    $r.cursor = 0;
                } else {
                    $r.cursor += 1;
                    $r.reset();
                    break;
                }
            } else {
                $r.cursor += 1;
            }
        }
    };
    ($r: expr, $n: expr) => {
        let mut acc = 0;
        $r.cursor += 1;
        loop {
            if $r.buf.get_unchecked($r.cursor) <= &b' ' {
                if $r.cursor >= $r.buf_len {
                    $r.buf_len = $r.stdin.read(&mut $r.buf).unwrap();
                    $r.cursor = 0;
                } else {
                    acc += 1;
                    $r.cursor += 1;
                    $r.reset();
                    if acc == $n {
                        break;
                    }
                }
            } else {
                $r.cursor += 1;
            }
        }
    };
}

struct Reader<'a>/*'*/ {
    stdin: StdinLock<'a>/*'*/,
    cursor: usize,
    buf_len: usize,
    buf: [u8; BUF_LEN],
    temp_end: usize,
    temp: [u8; 10_000],
}

impl Reader<'_>/*'*/ {
    #[inline]
    unsafe fn read(&mut self) -> &[u8] {
        let init = self.cursor;
        loop {
            if self.buf.get_unchecked(self.cursor) <= &b' ' {
                if self.cursor >= self.buf_len {
                    let s = self.buf_len.saturating_sub(init);

                    let src = self.buf.as_ptr().add(init);
                    let dest = self.temp.as_mut_ptr().add(self.temp_end);
                    std::ptr::copy_nonoverlapping(src, dest, s);

                    self.buf_len = self.stdin.read(&mut self.buf).unwrap();
                    self.temp_end += s;

                    if self.buf_len == 0 {
                        *self.temp.get_unchecked_mut(self.temp_end) = b'\n';
                        return &self.temp[..self.temp_end];
                    }

                    self.cursor = 0;

                    if s == 0 { self.reset(); }
                    return self.read();
                }

                if self.temp_end != 0 {
                    let s = self.cursor - init;
                    let n = self.temp_end + s;

                    let src = self.buf.as_ptr().add(init);
                    let dest = self.temp.as_mut_ptr().add(self.temp_end);
                    std::ptr::copy_nonoverlapping(src, dest, s);
                    *dest.add(s) = b'\n';

                    self.cursor += 1;
                    self.reset();
                    self.temp_end = 0;

                    return &self.temp[..n];
                }

                let t = self.cursor;
                self.cursor += 1;
                self.reset();
                return &self.buf[init..t];
            }
            self.cursor += 1;
        }
    }
    #[inline(always)]
    unsafe fn reset(&mut self) {
        while self.buf.get_unchecked(self.cursor) <= &b' ' {
            self.cursor += 1;
        }
    }
    #[inline(always)]
    unsafe fn read_with_lf_check(&mut self) -> (&[u8], bool) {
        let t = self.read();
        (t, *t.as_ptr().add(t.len()) < b' ')
    }
}

