const BUF_LEN: usize = 100_000;
fn main() {
    let stdin = stdin();
    let stdin = stdin.lock();
    let stdout = stdout();
    let stdout = stdout.lock();

    unsafe {
        solve(
            &mut Reader {
                stdin,
                cursor: 0,
                buf_len: 0,
                buf: [0; BUF_LEN],
                temp_end: 0,
                temp: [0; 10_000]
            },
            &mut BufWriter::with_capacity(100_000, stdout),
        );
    }
}

const M: usize = std::usize::MAX;
const REM: usize = 1_000_000_007;

fn bin_pow_rem(mut a: u128, mut b: u128, rem: u128) -> u128 {
    a %= rem;
    let mut res = 1;

    while b != 0 {
        if b&1 == 1 {
            res = res*a%rem;
        }
        a = a*a%rem;
        b >>= 1;
    }
    res
}

#[inline]
unsafe fn solve(r: &mut Reader, w: &mut BufWriter<StdoutLock>) {
    let n = read!(r, u128);
    wl!(w, "{}", bin_pow_rem(4, (1 << n) -2, REM as u128)*6 % REM as u128);
}
